/**
 * MedX main layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Main content region focus and overflow.
 */
const MAIN_TOKENS = Object.freeze({
  primary: { value: "layout-main-primary", scope: "layout" },
  secondary: { value: "layout-main-secondary", scope: "layout" },
  muted: { value: "layout-main-muted", scope: "layout" },
  accent: { value: "layout-main-accent", scope: "layout" },
  surface: { value: "layout-main-surface", scope: "layout" },
});

const MAIN_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const MAIN_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const mainRegistry = new Map();
const MAIN_listeners = new Set();
let MAIN_seq = 0;

function createMainId(prefix = "medx-layout-main") {
  MAIN_seq += 1;
  return `${prefix}-${MAIN_seq}`;
}

function registerMain(config = {}) {
  const entryId = config.id ?? createMainId();
  const preset = MAIN_PRESETS[config.preset ?? "default"] ?? MAIN_PRESETS.default;
  const token = MAIN_TOKENS[config.token ?? preset.token] ?? MAIN_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: MAIN_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  mainRegistry.set(entryId, entry);
  notifyMainListeners("register", entry);
  return entry;
}

function updateMain(id, patch = {}) {
  const entry = mainRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyMainListeners("update", entry);
  return entry;
}

function resolveMain(id) {
  const entry = mainRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listMainEntries(filter = {}) {
  let items = Array.from(mainRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onMainEvent(listener) {
  MAIN_listeners.add(listener);
  return () => MAIN_listeners.delete(listener);
}

function notifyMainListeners(type, entry) {
  for (const listener of MAIN_listeners) {
    try {
      listener({ type, entry, registrySize: mainRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:main] listener error", err.message);
    }
  }
}

function getMainMetrics() {
  const items = listMainEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(MAIN_TOKENS).length,
    presets: Object.keys(MAIN_PRESETS).length,
  };
}

async function runMedxMain() {
  console.log("[medx:ui:layout:main] runtime initialized");
  console.log(`[medx:ui:layout:main] tokens=${Object.keys(MAIN_TOKENS).length} presets=${Object.keys(MAIN_PRESETS).length}`);

  const events = [];
  onMainEvent((e) => events.push(e.type));

  const domains = Object.keys(MAIN_SUPPLY_CHAIN);
  const presets = Object.keys(MAIN_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerMain({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/main" },
    });
  }

  const first = listMainEntries()[0];
  if (first) updateMain(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getMainMetrics();
  const resolved = first ? resolveMain(first.id) : null;

  console.log(`[medx:ui:layout:main] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:main] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:main] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:main] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:main] bootstrap complete");
}

module.exports = runMedxMain;
